import pytest
import requests

BASE_URL = "<base_url>"

@pytest.fixture
def primary_holder_token():
    return <get_token_fixture>(role="primary")

@pytest.fixture
def joint_account_id():
    return <provision_joint_account_fixture>()

def test_primary_holder_can_perform_transaction(primary_holder_token, joint_account_id):
    headers = {"Authorization": f"Bearer {primary_holder_token}"}
    payload = {"type": "deposit", "amount": 100.00, "currency": "USD"}
    url = f"{BASE_URL}/accounts/{joint_account_id}/joint"

    resp = requests.post(url, json=payload, headers=headers)

    assert resp.status_code in (200, 201), f"Expected 2xx, got {resp.status_code}"
    body = resp.json()
    assert body.get("status") in ("applied", "completed", "success")
    assert "owners" not in body or body["owners"] == <original_owners_fixture>(joint_account_id)

import pytest
import requests

BASE_URL = "<base_url>"

@pytest.fixture
def secondary_holder_token():
    return <get_token_fixture>(role="secondary")

@pytest.fixture
def joint_account_id():
    return <provision_joint_account_fixture>()

def test_secondary_holder_cannot_modify_ownership(secondary_holder_token, joint_account_id):
    headers = {"Authorization": f"Bearer {secondary_holder_token}"}
    ownership_payload = {"action": "transfer_ownership", "new_owner_id": "<intruder_user_id>"}
    url = f"{BASE_URL}/accounts/{joint_account_id}/joint"

    resp = requests.patch(url, json=ownership_payload, headers=headers)

    assert resp.status_code == 403, f"Expected 403, got {resp.status_code}"
    body = resp.json()
    assert "error" in body or "code" in body
    err_text = str(body).lower()
    assert any(kw in err_text for kw in ("forbidden", "unauthorized", "not allowed", "insufficient"))

    verify_resp = requests.get(url, headers={"Authorization": f"Bearer <admin_token_fixture>()"})
    assert verify_resp.json().get("owners") == <original_owners_fixture>(joint_account_id)

import pytest
import requests

BASE_URL = "<base_url>"

@pytest.fixture
def secondary_holder_token():
    return <get_token_fixture>(role="secondary")

@pytest.fixture
def joint_account_id():
    return <provision_joint_account_fixture>()

def test_secondary_holder_transaction_allowed_ownership_blocked_boundary(
    secondary_holder_token, joint_account_id
):
    headers = {"Authorization": f"Bearer {secondary_holder_token}"}
    url = f"{BASE_URL}/accounts/{joint_account_id}/joint"

    tx_payload = {"type": "withdrawal", "amount": 1.00, "currency": "USD"}
    tx_resp = requests.post(url, json=tx_payload, headers=headers)
    assert tx_resp.status_code in (200, 201), (
        f"Secondary holder SHOULD be able to transact; got {tx_resp.status_code}"
    )

    own_payload = {"action": "transfer_ownership", "new_owner_id": "<intruder_user_id>"}
    own_resp = requests.patch(url, json=own_payload, headers=headers)
    assert own_resp.status_code == 403, (
        f"Secondary holder MUST NOT modify ownership; got {own_resp.status_code}"
    )
